    grammar:[
      {pattern:"～の他に(も)／～の他(に)は",explanation:"Means 'in addition to ~' or 'besides ~.' With も it adds; with は it excludes others.",ex:"ロボットの他にも、日本は自動車の技術でも有名だ。",tr:"In addition to robots, Japan is also famous for automobile technology.",note:"他に(も) = besides/in addition to. 他(に)は = other than (exclusive)."},
      {pattern:"(～と)同じ{ぐらい／くらい}",explanation:"Means 'about the same as ~,' expressing equality in degree or amount.",ex:"日本の新幹線はフランスのTGVと同じぐらい速い。",tr:"Japan's bullet train is about as fast as France's TGV.",note:"Can be used with adjectives, verbs, and amounts."},
      {pattern:"N＋型",explanation:"Attaches to a noun to mean '~ type' or '~ model,' categorizing something by its form or style.",ex:"人間型ロボットの研究が進んでいる。",tr:"Research on humanoid robots is progressing.",note:"Common: 新型 (new model), 旧型 (old model), A型 (type A)."},
      {pattern:"～として",explanation:"Means 'as ~,' indicating a role, capacity, or status.",ex:"日本は技術大国として知られている。",tr:"Japan is known as a technological powerhouse.",note:"The noun before として indicates the role or identity."},
      {pattern:"V-non-past＋ことになっている",explanation:"Expresses a rule, regulation, or established arrangement, meaning 'it is decided/expected that ~.'",ex:"この工場では、安全のためにヘルメットをかぶることになっている。",tr:"At this factory, it is the rule to wear a helmet for safety.",note:"Implies an impersonal decision or established practice, not a personal choice."},
      {pattern:"～てくる／～ていく",explanation:"～てくる expresses a change that has been developing up to now; ～ていく expresses a change that will continue into the future.",ex:"日本の技術は戦後大きく発展してきた。",tr:"Japanese technology has developed greatly since the postwar period.",note:"てくる = change toward the present; ていく = change away from the present into the future."},
      {pattern:"V-non-past＋ことになった",explanation:"Expresses that a decision has been made (often by others or an organization), meaning 'it has been decided that ~.'",ex:"来年から新しいシステムを導入することになった。",tr:"It has been decided that a new system will be introduced starting next year.",note:"Contrast with ことにした (I decided) — ことになった implies the decision is external."},
      {pattern:"～ように{頼む／言う}",explanation:"Used to report a request or instruction, meaning 'ask/tell someone to do ~.'",ex:"先生は学生にレポートを出すように言った。",tr:"The teacher told the students to submit their reports.",note:"The request content uses the plain non-past form + ように."},
      {pattern:"V-non-past＋ようにする",explanation:"Expresses making an effort or trying to do something habitually, meaning 'try to ~' or 'make sure to ~.'",ex:"毎日新しい技術のニュースを読むようにしている。",tr:"I make a point of reading news about new technology every day.",note:"ようにしている (ongoing habit) vs. ようにする (starting a new habit)."},
      {pattern:"～かな(あ)",explanation:"A sentence-ending expression meaning 'I wonder ~,' used when thinking aloud or expressing uncertainty.",ex:"この新しいアプリ、便利かなあ。",tr:"I wonder if this new app is convenient.",note:"Casual and reflective. Often used in internal monologue. Not used in formal speech."},
      {pattern:"なるべく",explanation:"An adverb meaning 'as much as possible' or 'if possible.'",ex:"なるべく最新の技術を使うようにしている。",tr:"I try to use the latest technology as much as possible.",note:"Slightly softer than できるだけ. Often pairs with ようにする."},
      {pattern:"～ようとした{が／けれど／ら}",explanation:"Expresses an attempt that was made but did not succeed, meaning 'tried to ~ but ~.'",ex:"新しいソフトをインストールしようとしたが、エラーが出た。",tr:"I tried to install the new software, but an error appeared.",note:"V-volitional + としたが expresses attempted but failed actions."},
    ],
